409	// C: #define lisdigit(c)   (testprop(c, DIGITBIT))
410	#[inline]
411	fn is_digit(c: i32) -> bool {
412	    c >= b'0' as i32 && c <= b'9' as i32
413	}
414	
415	// C: #define lisxdigit(c)  (testprop(c, XDIGITBIT))
416	#[inline]
417	fn is_xdigit(c: i32) -> bool {
418	    (c >= b'0' as i32 && c <= b'9' as i32)
419	        || (c >= b'a' as i32 && c <= b'f' as i32)
420	        || (c >= b'A' as i32 && c <= b'F' as i32)
