580	pub(crate) fn syntax_error(ls: &mut LexState, msg: &[u8]) -> LuaError {
581	    // C: lexerror(ls, msg, ls->t.token);
582	    let token = ls.t.kind;
583	    lex_error(ls, msg, token)
584	}
