586	// C: static const char *txtToken (LexState *ls, int token)
587	/// Produce a human-readable representation of `token` for error messages.
588	///
589	/// For `TK_NAME`, `TK_STRING`, `TK_FLT`, `TK_INT`: formats the current
590	/// token buffer contents as `'<text>'`.  For everything else, delegates to
591	/// [`token2str`].
592	///
593	/// # C source
594	/// ```c
595	/// // C: static const char *txtToken (LexState *ls, int token) {
596	/// //   switch (token) {
597	/// //     case TK_NAME: case TK_STRING:
598	/// //     case TK_FLT: case TK_INT:
599	/// //       save(ls, '\0');
600	/// //       return luaO_pushfstring(ls->L, "'%s'", luaZ_buffer(ls->buff));
601	/// //     default:
602	/// //       return luaX_token2str(ls, token);
603	/// //   }
604	/// // }
605	/// ```
606	///
607	/// PORT NOTE: C calls `luaO_pushfstring` which pushes the string onto the
608	/// Lua stack (stack-anchored temporary).  Rust returns `Vec<u8>` directly
609	/// since there is no stack-based string lifecycle for error formatting.
610	fn txt_token(ls: &mut LexState, token: i32) -> Vec<u8> {
611	    match token {
612	        // C: case TK_NAME: case TK_STRING: case TK_FLT: case TK_INT:
613	        t if t == TK_NAME || t == TK_STRING || t == TK_FLT || t == TK_INT => {
614	            // C: save(ls, '\0') — NUL-terminate the buffer for use as C string
615	            // In Rust we don't NUL-terminate; use the live bytes directly.
616	            // C: return luaO_pushfstring(ls->L, "'%s'", luaZ_buffer(ls->buff));
617	            // macros.tsv: luaZ_buffer → buf.as_mut_slice()
618	            let mut v: Vec<u8> = Vec::new();
619	            v.push(b'\'');
620	            v.extend_from_slice(ls.buff.as_slice());
621	            v.push(b'\'');
622	            v
623	        }
624	        // C: default: return luaX_token2str(ls, token);
625	        _ => token2str_raw(token),
626	    }
627	}
