#[derive(Debug)]
pub struct LexState {
    /// C: current — current character (i32; -1 = EOZ)
    pub current: i32,
    /// C: linenumber
    pub linenumber: i32,
    /// C: lastline
    pub lastline: i32,
    /// C: t — current token
    pub t: LexToken,
    /// C: lookahead — one-token lookahead
    pub lookahead: LexToken,
    /// C: fs — current FuncState (parser owns this)
    pub fs: Option<Box<FuncState>>,
    /// C: dyd — parser dynamic data
    pub dyd: DynData,
